-- ============================================================
-- LAB - Actualizacion de rosters 2026 (desde rosters_2026.md)
-- ============================================================

DO $$
DECLARE
  temp_id UUID;
  arias_id UUID;
  cachorros_id UUID;
  infernales_id UUID;
  daom_id UUID;
  falcons_id UUID;
BEGIN
  SELECT id INTO temp_id FROM temporadas WHERE anio = 2026;
  SELECT id INTO arias_id FROM clubes WHERE slug = 'arias';
  SELECT id INTO cachorros_id FROM clubes WHERE slug = 'cachorros';
  SELECT id INTO infernales_id FROM clubes WHERE slug = 'infernales';
  SELECT id INTO daom_id FROM clubes WHERE slug = 'daom';
  SELECT id INTO falcons_id FROM clubes WHERE slug = 'falcons';

  DELETE FROM jugadores WHERE club_id IN (arias_id, cachorros_id, infernales_id, daom_id, falcons_id);


  -- Staff tecnico provisto en el archivo fuente (Arias y Popeye/Infernales)
  DELETE FROM staff_clubes WHERE club_id IN (arias_id, infernales_id) AND cargo IN ('Manager','Bench Coach','Pitching Coach','Coach','Jefe de equipo');
END $$;
